fun formatDate(
    day: Int,
    month: Int,
    year: Int,
    separator: String = "-"
): String {
    return "$day$separator$month$separator$year"
}

fun main() {
    val date1 = formatDate(15, 7, 2026)
    println(date1)  // 15-7-2026

    val date2 = formatDate(
        year = 2026,
        month = 7,
        day = 15,
        separator = "/"
    )
    println(date2)  // 15/7/2026
}
